import React from 'react';

function OfficialSite({ setActivePage }) {
  return (
    <div className="fixed inset-0 z-[100] bg-white flex flex-col">
      {/* Navigation Header for Kiosk */}
      <div className="bg-[#6f5c4e] text-white p-4 flex justify-between items-center shadow-md">
        <div className="flex items-center gap-4">
          <h2 className="font-semibold text-lg">Indus University Official Website</h2>
        </div>
        <button 
          onClick={() => setActivePage('home')}
          className="bg-white text-[#6f5c4e] px-6 py-2 rounded-full font-bold hover:bg-gray-100 transition-colors shadow-sm"
        >
          Back to Kiosk
        </button>
      </div>

      {/* The Iframe */}
      <div className="flex-1 w-full bg-gray-100 relative">
        <iframe 
          src="https://indusuni.ac.in/" 
          className="w-full h-full border-none"
          title="Indus University Official Website"
          allow="autoplay; clipboard-write; encrypted-media; picture-in-picture; web-share"
        ></iframe>

        {/* Overlay helper if blocked */}
        <div className="absolute inset-0 flex items-center justify-center pointer-events-none opacity-0 hover:opacity-100 transition-opacity bg-black/5">
           <p className="text-gray-400 text-sm">Official Website View</p>
        </div>
      </div>
    </div>
  );
}

export default OfficialSite;
